package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnCommentDeleteProxy struct {
	automation.UnimplementedOnCommentDeleteServer
	client automation.OnCommentDeleteClient
}

func init() {
	proxyutil.Register(&automation.OnCommentDelete_ServiceDesc, NewOnCommentDeleteProxy)
}
func NewOnCommentDeleteProxy(cc grpc.ClientConnInterface) automation.OnCommentDeleteServer {
	return &OnCommentDeleteProxy{client: automation.NewOnCommentDeleteClient(cc)}
}
func (p *OnCommentDeleteProxy) OnCommentDelete(ctx context.Context, in *events.CommentDelete) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.CommentDelete, automation.HandlerResult](p.client.OnCommentDelete)(ctx, in)
}
